  1→use serde::{Deserialize, Serialize};
  2→use std::collections::HashSet;
  3→use std::fs;
  4→use std::path::{Path, PathBuf};
  5→
  6→#[derive(Debug, Serialize, Deserialize, Clone, Default)]
  7→pub struct EntireSettings {
  8→    pub enabled: Option<bool>,
  9→    pub local_dev: Option<bool>,
 10→    pub log_level: Option<String>,
 11→    pub telemetry: Option<bool>,
 12→}
 13→
 14→/// Read .entire/settings.json from a repo
 15→pub fn read_settings(repo_path: &str) -> Result<EntireSettings, String> {
 16→    let settings_path = Path::new(repo_path).join(".entire/settings.json");
 17→    if !settings_path.exists() {
 18→        return Err("No .entire/settings.json found".to_string());
 19→    }
 20→
 21→    let content =
 22→        fs::read_to_string(&settings_path).map_err(|e| format!("Failed to read settings: {}", e))?;
 23→
 24→    serde_json::from_str(&content).map_err(|e| format!("Failed to parse settings: {}", e))
 25→}
 26→
 27→/// Check if a repo has Entire enabled
 28→pub fn is_entire_enabled(repo_path: &str) -> bool {
 29→    let entire_dir = Path::new(repo_path).join(".entire");
 30→    if !entire_dir.exists() {
 31→        return false;
 32→    }
 33→    match read_settings(repo_path) {
 34→        Ok(settings) => settings.enabled.unwrap_or(false),
 35→        Err(_) => false,
 36→    }
 37→}
 38→
 39→// --- Registry persistence for manually registered repos ---
 40→
 41→#[derive(Debug, Serialize, Deserialize, Default)]
 42→struct RepoRegistry {
 43→    repos: Vec<String>,
 44→}
 45→
 46→fn registry_path() -> PathBuf {
 47→    let home = dirs_next().unwrap_or_default();
 48→    PathBuf::from(home).join(".entire").join("registered-repos.json")
 49→}
 50→
 51→fn load_registered_repos() -> Vec<String> {
 52→    let path = registry_path();
 53→    let content = match fs::read_to_string(&path) {
 54→        Ok(c) => c,
 55→        Err(_) => return Vec::new(),
 56→    };
 57→    match serde_json::from_str::<RepoRegistry>(&content) {
 58→        Ok(reg) => reg.repos,
 59→        Err(_) => Vec::new(),
 60→    }
 61→}
 62→
 63→fn save_registered_repos(repos: &[String]) -> Result<(), String> {
 64→    let path = registry_path();
 65→    if let Some(parent) = path.parent() {
 66→        fs::create_dir_all(parent).map_err(|e| format!("Failed to create ~/.entire: {}", e))?;
 67→    }
 68→    let registry = RepoRegistry {
 69→        repos: repos.to_vec(),
 70→    };
 71→    let content =
 72→        serde_json::to_string_pretty(&registry).map_err(|e| format!("Failed to serialize: {}", e))?;
 73→    fs::write(&path, content).map_err(|e| format!("Failed to write registry: {}", e))
 74→}
 75→
 76→pub fn register_repo(path: &str) -> Result<(), String> {
 77→    let p = Path::new(path);
 78→
 79→    if !p.is_dir() {
 80→        return Err("Path is not a directory".to_string());
 81→    }
 82→
 83→    // Validate it's a git repo
 84→    git2::Repository::open(p).map_err(|_| "Not a git repository".to_string())?;
 85→
 86→    // If .entire/settings.json doesn't exist or isn't enabled, create it
 87→    if !is_entire_enabled(path) {
 88→        let entire_dir = p.join(".entire");
 89→        fs::create_dir_all(&entire_dir)
 90→            .map_err(|e| format!("Failed to create .entire directory: {}", e))?;
 91→        let settings = EntireSettings {
 92→            enabled: Some(true),
 93→            local_dev: None,
 94→            log_level: None,
 95→            telemetry: None,
 96→        };
 97→        let content = serde_json::to_string_pretty(&settings)
 98→            .map_err(|e| format!("Failed to serialize settings: {}", e))?;
 99→        fs::write(entire_dir.join("settings.json"), content)
100→            .map_err(|e| format!("Failed to write settings: {}", e))?;
101→    }
102→
103→    // Canonicalize to avoid duplicates from different path representations
104→    let canonical = p
105→        .canonicalize()
106→        .map_err(|e| format!("Failed to resolve path: {}", e))?
107→        .to_string_lossy()
108→        .to_string();
109→
110→    let mut repos = load_registered_repos();
111→    if repos.contains(&canonical) {
112→        return Ok(()); // Already registered, not an error
113→    }
114→
115→    repos.push(canonical);
116→    save_registered_repos(&repos)
117→}
118→
119→pub fn unregister_repo(path: &str) -> Result<(), String> {
120→    let mut repos = load_registered_repos();
121→    let canonical = Path::new(path)
122→        .canonicalize()
123→        .map(|p| p.to_string_lossy().to_string())
124→        .unwrap_or_else(|_| path.to_string());
125→
126→    repos.retain(|r| r != &canonical && r != path);
127→    save_registered_repos(&repos)
128→}
129→
130→pub fn get_registered_repos() -> Vec<String> {
131→    load_registered_repos()
132→}
133→
134→// --- Hidden repos persistence (for excluding discovered repos) ---
135→
136→#[derive(Debug, Serialize, Deserialize, Default)]
137→struct HiddenRegistry {
138→    repos: Vec<String>,
139→}
140→
141→fn hidden_registry_path() -> PathBuf {
142→    let home = dirs_next().unwrap_or_default();
143→    PathBuf::from(home).join(".entire").join("hidden-repos.json")
144→}
145→
146→fn load_hidden_repos() -> Vec<String> {
147→    let path = hidden_registry_path();
148→    let content = match fs::read_to_string(&path) {
149→        Ok(c) => c,
150→        Err(_) => return Vec::new(),
151→    };
152→    match serde_json::from_str::<HiddenRegistry>(&content) {
153→        Ok(reg) => reg.repos,
154→        Err(_) => Vec::new(),
155→    }
156→}
157→
158→fn save_hidden_repos(repos: &[String]) -> Result<(), String> {
159→    let path = hidden_registry_path();
160→    if let Some(parent) = path.parent() {
161→        fs::create_dir_all(parent).map_err(|e| format!("Failed to create ~/.entire: {}", e))?;
162→    }
163→    let registry = HiddenRegistry {
164→        repos: repos.to_vec(),
