              <div className="flex min-w-0 flex-1 flex-col overflow-hidden">
                {/* Inner tabs */}
                <div className="flex gap-1 border-b border-border-subtle bg-bg px-4 py-2">
                  {(["chat", "checkpoints", "diff", "insights", "debug"] as const).map((tab) => (
