  console.log(`[planning] Replaying ${buffered.length} buffered events for ${agentSessionId}`);
  pendingAgentEventsRef.current.delete(agentSessionId);
  for (const evt of buffered) {
    // Re-dispatch by emitting synthetic CustomEvents that Tauri listeners pick up
    // We use window.dispatchEvent with the same payload shape
    if (evt.type === "output") {
      window.dispatchEvent(new CustomEvent("__agent-output-replay", { detail: evt.payload }));
    } else if (evt.type === "done") {
      window.dispatchEvent(new CustomEvent("__agent-done-replay", { detail: evt.payload }));
    }
  }
}

