// Stream stdout line-by-line to the frontend
{
    let id = session_id.clone();
    let app_handle = app.clone();
    let state_for_wait = state.inner().clone();

    thread::spawn(move || {
        eprintln!("[agent:{}] stdout reader started", id);
        let reader = BufReader::new(stdout);
        let mut line_count = 0u64;
        for line in reader.lines() {
            match line {
                Ok(text) if !text.is_empty() => {
                    line_count += 1;
                    // Log every line with type info for debugging
                    let type_hint = if let Ok(v) = serde_json::from_str::<serde_json::Value>(&text) {
                        let t = v.get("type").and_then(|t| t.as_str()).unwrap_or("?");
                        let sub = v.get("subtype").and_then(|s| s.as_str()).unwrap_or("");
                        if sub.is_empty() { t.to_string() } else { format!("{}/{}", t, sub) }
                    } else {
                        "non-json".to_string()
                    };
                    eprintln!("[agent:{}] line {}: type={} len={}", id, line_count, type_hint, text.len());
                    let _ = app_handle.emit(
                        "agent-output",
                        AgentOutputPayload {
                            session_id: id.clone(),
                            data: text,
                        },
                    );
                }
                Ok(_) => {} // skip empty lines
                Err(e) => {
                    eprintln!("[agent:{}] stdout error: {}", id, e);
                    break;
                }
            }
        }
        eprintln!("[agent:{}] stdout EOF after {} lines", id, line_count);

        // Wait for the child process to exit and capture the real exit code
        let exit_code = if let Ok(mut state) = state_for_wait.lock() {
            if let Some(session) = state.sessions.get_mut(&id) {
                match session.child.try_wait() {
                    Ok(Some(status)) => {
                        eprintln!("[agent:{}] exited with code {:?}", id, status.code());
                        status.code()
                    }
                    _ => None,
                }
            } else {
                None
            }
        } else {
            None
        };

        let _ = app_handle.emit("agent-done", AgentDonePayload {
            session_id: id,
            exit_code,
        });
    });
}

