#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    tauri::Builder::default()
        .plugin(tauri_plugin_opener::init())
        .plugin(tauri_plugin_dialog::init())
        .plugin(tauri_plugin_window_state::Builder::default().build())
        .manage(Mutex::new(AppState {
            watched_repos: HashSet::new(),
        }))
        .manage(Mutex::new(pty::PtyState::new()))
        .manage(Mutex::new(agent::AgentState::new()))
        .setup(|app| {
            // Round the window corners on macOS (decorations: false)
            {
                use tauri::Manager;
                if let Some(window) = app.get_webview_window("main") {
                    use raw_window_handle::{HasWindowHandle, RawWindowHandle};
                    if let Ok(handle) = window.window_handle() {
                        if let RawWindowHandle::AppKit(handle) = handle.as_raw() {
                            use objc2::msg_send;
                            use objc2::runtime::AnyObject;
                            let ns_view = handle.ns_view.as_ptr() as *mut AnyObject;
                            unsafe {
                                let ns_window: *mut AnyObject = msg_send![ns_view, window];
                                // Make the window background fully transparent so
                                // rounded corners don't show a black triangle
                                let _: () = msg_send![ns_window, setOpaque: false];
                                let ns_color_class = objc2::runtime::AnyClass::get(
                                    c"NSColor"
                                ).unwrap();
                                let clear_color: *mut AnyObject = msg_send![ns_color_class, clearColor];
                                let _: () = msg_send![ns_window, setBackgroundColor: clear_color];
                                let _: () = msg_send![ns_window, setHasShadow: true];
                                // Get the content view and round its corners
                                let content_view: *mut AnyObject = msg_send![ns_window, contentView];
                                let _: () = msg_send![content_view, setWantsLayer: true];
                                let layer: *mut AnyObject = msg_send![content_view, layer];
                                let _: () = msg_send![layer, setCornerRadius: 10.0f64];
                                let _: () = msg_send![layer, setMasksToBounds: true];
                                // Set the content view's background to the app bg color
                                let bg_color: *mut AnyObject = msg_send![
                                    ns_color_class,
                                    colorWithRed: 0.043f64,
                                    green: 0.043f64,
                                    blue: 0.051f64,
                                    alpha: 1.0f64
                                ];
                                let cg_color: *mut AnyObject = msg_send![bg_color, CGColor];
                                let _: () = msg_send![layer, setBackgroundColor: cg_color];
                            }
                        }
                    }
                }
            }

            // System tray
            use tauri::menu::{MenuBuilder, MenuItemBuilder};
            use tauri::tray::TrayIconBuilder;
            use tauri::Manager;

            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
            let menu = MenuBuilder::new(app)
                .item(&show)
                .separator()
                .item(&quit)
                .build()?;

            let _tray = TrayIconBuilder::new()
                .tooltip("Entire Desktop")
                .menu(&menu)
                .on_menu_event(move |app, event| {
                    match event.id().as_ref() {
                        "show" => {
                            if let Some(window) = app.get_webview_window("main") {
                                let _ = window.show();
                                let _ = window.set_focus();
                            }
                        }
                        "quit" => {
                            app.exit(0);
                        }
                        _ => {}
                    }
                })
                .on_tray_icon_event(|tray, event| {
                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
                        let app = tray.app_handle();
                        if let Some(window) = app.get_webview_window("main") {
                            let _ = window.show();
                            let _ = window.set_focus();
                        }
                    }
                })
                .build(app)?;

            delta::events::start_delta_watcher(app.handle().clone())
                .unwrap_or_else(|e| eprintln!("[delta] watcher failed to start: {e}"));

            Ok(())
        })
        .invoke_handler(tauri::generate_handler![
            debug_log,
            list_repos,
            register_repo,
            unregister_repo,
            hide_repo,
            create_worktree,
            create_agent_worktree,
            delete_worktree,
            delete_branch,
            list_checkpoints,
            get_diff_stats,
            get_transcript,
            get_checkpoint_diff,
            run_checkpoint_semantic_review,
            get_branch_diff,
            list_sessions,
            get_entire_settings,
            get_entire_logs,
            get_checkpoint_logs,
            get_raw_checkpoint_metadata,
            get_raw_session_file,
            list_trails,
            watch_repo,
            pty::pty_create,
            pty::pty_write,
            pty::pty_resize,
            pty::pty_destroy,
            agent::agent_create,
            agent::agent_destroy,
            agent::agent_write,
            delta_create,
            delta_list,
            delta_get,
            delta_get_plan,
            delta_update_plan,
            delta_get_dag,
            delta_get_tasks,
            delta_get_events,
            delta_delete,
            delta_workspace_path,
            delta_approve_plan,
            delta_answer_question,
            delta_cancel,
        ])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}

